954→    public Map<Integer, List<ProducerBatch>> drain(MetadataSnapshot metadataSnapshot, Set<Node> nodes, int maxSize, long now) {
   955→        if (nodes.isEmpty())
   956→            return Collections.emptyMap();
   957→
   958→        Map<Integer, List<ProducerBatch>> batches = new HashMap<>();
   959→        for (Node node : nodes) {
   960→            List<ProducerBatch> ready = drainBatchesForOneNode(metadataSnapshot, node, maxSize, now);
